var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"에휴......","JPN":"まったく……","ENG":"Ugh...","TWN":"唉……"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여기도 완전히 박살 나 버렸네.","JPN":"ここも完全に破壊されてしまったな。","ENG":"So this place is completely destroyed, too.","TWN":"這裡也被破壞了。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이제야 겨우 정착한 줄 알았는데, 이러면 또 떠돌이 신세잖아.","JPN":"やっと定着したと思ったが……こんなんじゃあ、また放浪の身になるじゃないか。","ENG":"I thought we were finally settling down. Now we've got to hit the road again.","TWN":"還以為終於定居了，這樣一來又得流浪了。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그 괴물이 강림했을 때의 여파가 지하실 통로 너머까지 퍼져나갔으니까.","JPN":"あの化け物が降臨したときの余波が地下室の通路の先まで広まっちゃったからね。","ENG":"Yeah, who knew the effects of that monster's arrival would reach beyond the portal all the way out here?","TWN":"那個怪物降臨的時候，直接影響了地下室通道的那一邊。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그나마 운 나쁘게 휘말린 사람이 없어서 다행이야.","JPN":"でも、巻き込まれた人がいなくてよかったわ。","ENG":"At least nobody got swept up in all of that creepy destruction.","TWN":"所幸沒有人被捲入。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래. 그 괴물 말이야.","JPN":"そうだよ。あの怪物だ。","ENG":"Speaking of that monster...","TWN":"是啊，那個怪物。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하아...... 최초의 인형이나 발푸르기스 성 보수작업만으로도 머리 아파 죽겠는데 그 괴물은 또 뭐람?","JPN":"はあ……最初の人形やヴァルプルギス城の補修作業だけで\\n十分大変なのに、あの怪物は何なんだ。","ENG":"What's the deal with that monster? It's already enough tracking down the Original Puppet and repairing the Walpurgis Castle.","TWN":"哈啊……最初的木偶和魔女之夜城的修繕工作已經讓我很頭疼了，怎麼還出現個怪物？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"인형의 주인을 벌레 잡듯 없애 버리다니...... 그런 괴물이 갑자기 어디서 나타난 걸까......","JPN":"人形の持ち主を完膚なきまでに消してしまうなんて……\\nあんな化け物どこから現れたんだろう……","ENG":"I mean, it just got rid of the Puppet Master instantly, as if swatting a fly. Where did something like that come from?","TWN":"木偶之主在它面前就像個螻蟻……那怪物到底是從哪裡來的呢……"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"괴물에 대해서는 앞으로 알아 봐야겠지만, 새로 알게 된 사실도 하나 있어.","JPN":"怪物については今から調べる必要があるけど、初めて知った事実も一つあったわ。","ENG":"We'll have to do more research on the monster, but there is something new we could learn.","TWN":"那個怪物還得再調查一下，不過我倒是有新發現。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭔데?","JPN":"何だ？","ENG":"And what's that?","TWN":"是什麼？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그 무시무시한 최초의 인형이 사실은 마조히스트 변태였다는 것.","JPN":"あの恐ろしい最初の人形は、実はドMだったってこと。","ENG":"That the formidable Original Puppet turned out to be just a perverted masochist.","TWN":"那個可怕的最初的木偶其實就是個超級受虐狂。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"풉! 하하하!","JPN":"ぷっ！　ははは！","ENG":"Pfft! Hah hah hah!","TWN":"噗！哈哈哈！"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아, 그건 정말 웃겼어.","JPN":"ああ、今のは本当にウケた。","ENG":"Ah, good one.","TWN":"啊，那確實很搞笑。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"자기가 만든 인형을 주인님이라고 부르면서 괴롭혀 달라고 졸랐다는 거 아냐.","JPN":"自分で作った人形をマスターと呼びながら、苦しめてほしいとねだっていたな。","ENG":"Just imagine her begging her own puppet to torture her, calling it \\"Master.\\"","TWN":"居然把自己做成的木偶叫做主人，還讓木偶折磨自己。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"나였으면 부끄러워서라도 평생 성 안에 틀어박혀 있었을 걸.","JPN":"妾だったら恥ずかしくて一生城の中に閉じこもっただろう。","ENG":"I'd be so ashamed of myself that I would have never left that castle, if I were her.","TWN":"換做是我，丟臉丟得都不敢走出城門，估計一輩子就老死在城裡了。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇긴 한데, 너 그 얘기 들을 때는 고개도 못 들고 부들부들 떨고 있지 않았어?","JPN":"それはそうだけど……あなたその話を聞いてる時、\\n頭を下げたままぶるぶる震えてなかった？","ENG":"Says the person who was too scared to even look up when she told us that. You were trembling like a lost puppy.","TWN":"可是，那個傢伙那麼說的時候，妳不是連頭都不敢抬，一直在那裡抖個不停嗎？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그, 그건 어쩔 수 없잖아!","JPN":"そ、それは仕方ないだろう！","ENG":"W-well, I couldn't help it!","TWN":"那、那是沒辦法吧！"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그 녀석은...... 우리 세계를 멸망시킨 원흉이니까.","JPN":"あいつは……妾たちの世界を滅ぼした元凶だからな。","ENG":"She... destroyed our home world.","TWN":"因為那個傢伙……是毀滅了我們世界的真凶。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"우리가 이 세계로 떠밀려 온 지 얼마나 지났지?","JPN":"妾たちがこの世界に流れてきてからどのくらい時間が経った？","ENG":"How many years has it been since we've drifted to this world anyway?","TWN":"我們來到這個世界有多久了？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"글쎄, 얼마나 됐더라? 요즘엔 세는 것도 잊어 버렸네.","JPN":"さあね、どうかしら？　最近は数えることも忘れてしまったわ。","ENG":"I don't know... I lost count these days.","TWN":"是啊，多久了？我都不記得了。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"엑자일러인 우리가 이 세계에서 살아남을 수 있었던 건 메이 할머니의 마법 덕분이었어.","JPN":"エグザイラーである私たちがこの世界で\\n生き残ることができたのはメイお婆ちゃんの魔法のおかげよ。","ENG":"It was thanks to Granny May's magic that Exiles like us managed to survive in this world for so long.","TWN":"多虧了梅伊奶奶的魔法，我們才能在這個世界上存活下去。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하지만 메이 할머니가 돌아가셨으니 마법도 점점 약해지겠지.","JPN":"でもメイお婆ちゃんが亡くなったから、魔法の力もどんどん弱くなっていくと思うわ。","ENG":"But now with Granny May gone, the magic will also grow faint.","TWN":"但梅伊奶奶去世了，魔法也會漸漸變弱吧。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"우리에게 남은 시간은 아마......","JPN":"私たちに残ってる時間は多分……","ENG":"We probably don't have much time left...","TWN":"我們所剩的時間……"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아, 진짜! 꼭 지금 그런 이야길 해야겠어? 당장 죽는 것도 아닌데.","JPN":"ああ、もう！　こんな時に持ち出す話じゃないだろう？　今すぐ死ぬわけじゃないし。","ENG":"Oh, come on! Do we have to talk about that now? It's not like we're going to die anytime soon.","TWN":"真是！妳非得現在說那種話嗎？又不是馬上就要死了。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래? 내 연구로는 뾰족한 수가 안 나오던데, 무슨 대책이라도 있어?","JPN":"そう？　私の研究ではこれといった方法はなかったのだけど、何かあるの？","ENG":"You think so? I couldn't figure out anything with all my research. Have you got any plans?","TWN":"是嗎？我自己研究不出個所以然來，難道妳有什麼對策？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"남아 있는 마도구로 마법의 지속 기간을 늘리면 한동안은 괜찮을 거야.","JPN":"残りの魔道具で魔法の持続時間を増やせばしばらくの間は大丈夫だろう。","ENG":"I'm sure we'll be fine for the time being if we can extend the life of the magic with the instruments we've got left.","TWN":"用剩下的魔導具延長魔法的持續時間，還是能撐一段時間的。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그리고 어쩌면......","JPN":"そして、もしかしたら……","ENG":"And it just might be possible...","TWN":"而且，也許……"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"우리의 견습 대마녀께서 다른 방법을 찾아 줄지도 모르지.","JPN":"見習い大魔女が他の方法を見つけてくれるかもしれないしな。","ENG":"that our Great Witch-in-training may find us another way.","TWN":"我們的見習大魔女說不定能找到其他辦法。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"유나 말이야?","JPN":"ユナのこと？","ENG":"You mean Yuna?","TWN":"妳是說尤娜？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"확실히 메이 할머니를 닮아서 재능은 대단한데......","JPN":"確かにメイお婆ちゃんに似て才能はあるようだけど……","ENG":"She sure seems talented like her grandmother...","TWN":"尤娜很像梅伊奶奶，能力非常出眾……"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"혹시 거기까지 내다보고 솔라 코덱스를 전해 준 거야?","JPN":"もしかして、そこまで見極めてソーラーコーデックスを渡したの？","ENG":"But is that why you gave her the Solar Codex?","TWN":"所以妳才早早地把太陽法典給了她？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇다면 역시 베아트릭스의 딸은 대단하다고 칭찬해 줘야겠는걸?","JPN":"それならやっぱりベアトリクスの娘はすごいって褒めてあげなくちゃね！","ENG":"If that's the case, I've got to admit the daughter of Beatrix has a pretty impressive prescience.","TWN":"那麼，我是不是該稱讚一下蘿拉呢？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그럴 리가 있겠냐?","JPN":"そんなはずないだろう。","ENG":"Don’t be ridiculous.","TWN":"怎麼可能？"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그때도 말했잖아. 그냥 애물단지 하나 치운 거라고.","JPN":"あの時も言ってたじゃないか。ただ厄介者を片付けただけだと。","ENG":"I told you. I was just trying to get rid of the book because it was useless for us.","TWN":"我那時候也說過，只是覺得我們留著那本書也沒什麼用。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래도 지금의 모습을 보면...... 나도 조금은 기대하게 돼.","JPN":"でも今の姿を見てると……少しは期待していいかもしれない。","ENG":"But when I see her now... she does get my hopes up a bit.","TWN":"不過，她現在的模樣……我倒是有點期待了。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"유나가 이대로 성장하면 언젠가는......","JPN":"ユナがこのまま成長すればいつか……","ENG":"If Yuna continues to grow at this rate...","TWN":"尤娜如果一直這麼成長下去，遲早有一天……"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"발푸르기스의 성을 완전히 수복해서 다시 우리의 고향으로 돌아갈 수 있기를.","JPN":"ヴァルプルギス城を修復して、私たちの故郷に帰れますように。","ENG":"Someday, we just might fully recover Walpurgis Castle and return home.","TWN":"希望能完全修好魔女之夜城，讓我們重回家鄉。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래. 그게 모든 엑자일러......","JPN":"そう。それはすべてのエグザイラー……","ENG":"Yes, that's what every Exile...","TWN":"嗯，那其實就是所有流浪者……"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"세계의 방랑자들의 꿈이니까.","JPN":"世界を放浪する者たちの夢だから。","ENG":"every World Wanderer dreams of.","TWN":"所有流浪者的夢想。"},"stage":{"bg":"SS_STREGA_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......좋아, 그럼 그때까지 먹고 살수 있도록 카페 2호점을 차려야겠네.","JPN":"……よし。じゃあその日まで生き残るために、カフェ2号店を出店しないとね。","ENG":"Alright, then. I guess we'll have to open another cafe if we want to keep ourselves afloat till that day comes.","TWN":"……好吧，那就為了撐到那時候，趕緊開個咖啡2號店吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"유나와 잉그리드가 신나서 여기저기 장소를 물색하고 있던걸?","JPN":"ユナとイングリッドが喜んでいろんな場所を下見してたわよ。","ENG":"Yuna and Ingrid were already looking for a new spot. They seemed pretty excited about it.","TWN":"尤娜和英格麗好像特別興奮，正在到處找合適的位置呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"으엑?! 그 녀석들이? 또 무슨 사고를 치려고!","JPN":"ええっ、あいつらが？　またやらかすつもりか！","ENG":"What? Those rascals again? What are they going to do this time?","TWN":"啊？！她們？不會又闖什麼禍吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"안되겠다! 당장 가봐야겠어!! 유나! 잉그리드!!","JPN":"ダメだ！　すぐに行かないと！！　ユナ！　イングリッド！！","ENG":"That's it. I've got to go keep an eye on them! Yuna! Ingrid!","TWN":"不行！我得跟去看看！！尤娜！英格麗！！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"으허억!!","JPN":"うわあっ！？","ENG":"Eeek!","TWN":"啊呀！！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLATTER"},{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아 참, 바닥에 건물 잔해가 많으니까 넘어지지 않게 조심하라고.","JPN":"あ、床に建物の残骸がたくさん残ってるから、転ばないように気を付けてね。","ENG":"Oh, by the way... Watch out for the rubble on the floor.","TWN":"對了，地上到處都是殘骸，小心不要被絆倒哦。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐아옹~","JPN":"にゃああ～。","ENG":"Meow!","TWN":"喵喵~"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};